using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }

    public int OriginalLength { get; set; }

    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
        "that", "from", "as", "be", "has", "have", "had", "do", "does",
        "did", "will", "would", "could", "should", "may", "might", "not",
        "no", "so", "if", "then", "than", "too", "very", "can", "just",
        "about", "into", "over", "after", "before", "between", "under",
        "again", "there", "here", "all", "each", "every", "both", "few",
        "more", "most", "other", "some", "such", "only", "own", "same",
        "also", "been", "being", "its", "which", "who", "whom", "what",
        "when", "where", "how", "while", "during", "through", "up", "out"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
        {
            return string.Join(" ", sentences);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top sentences, then restore original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    freq[word] = freq.GetValueOrDefault(word) + 1;
                }
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            if (words.Count == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w] / (double)maxFreq);

            // Normalize by word count to avoid bias toward long sentences.
            score /= words.Count;

            scored.Add((i, score));
        }

        return scored;
    }

    private static List<string> ExtractWords(string text) =>
        WordPattern().Matches(text).Select(m => m.Value).ToList();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

